  const CC_DISPLAY = {AE:"United Arab Emirates",AL:"Albania",AM:"Armenia",AT:"Austria",AZ:"Azerbaijan",BA:"Bosnia & Herzegovina",BE:"Belgium",BG:"Bulgaria",BH:"Bahrain",BY:"Belarus",CH:"Switzerland",CY:"Cyprus",CZ:"Czechia",DE:"Germany",DZ:"Algeria",EG:"Egypt",ES:"Spain",FR:"France",GB:"United Kingdom",GE:"Georgia",GR:"Greece",HR:"Croatia",HU:"Hungary",IL:"Israel",IQ:"Iraq",IR:"Iran",IT:"Italy",JO:"Jordan",KW:"Kuwait",KZ:"Kazakhstan",LB:"Lebanon",LT:"Lithuania",LU:"Luxembourg",LY:"Libya",MD:"Moldova",ME:"Montenegro",MK:"North Macedonia",NL:"Netherlands",OM:"Oman",PL:"Poland",PS:"Palestine",QA:"Qatar",RO:"Romania",RS:"Serbia",RU:"Russia",SA:"Saudi Arabia",SI:"Slovenia",SK:"Slovakia",SY:"Syria",TM:"Turkmenistan",TN:"Tunisia",TR:"Türkiye",UA:"Ukraine",UZ:"Uzbekistan",XK:"Kosovo",DK:"Denmark",EE:"Estonia",FI:"Finland",FO:"Faroe Islands",GI:"Gibraltar",IE:"Ireland",IS:"Iceland",LV:"Latvia",MA:"Morocco",NO:"Norway",PT:"Portugal",SE:"Sweden"};

  const CITY_DICT = (() => {
    // parse the raw blob once into parallel arrays (compact, fast to scan)
    const names = [], cc = [], lats = [], lons = [], pops = [], lower = [];
    for (const row of (GEONAMES_RAW + '|' + GEONAMES_RAW_WEST).split('|')) {
      const f = row.split(';');
      if (f.length < 5) continue;
      names.push(f[0]);
      cc.push(f[1]);
      lats.push(+f[2]);
      lons.push(+f[3]);
      pops.push(+f[4]);
      lower.push(f[0].toLowerCase());
    }
    const countryName = (code) => CC_DISPLAY[code] || code || '';

    // search: case-insensitive prefix-first match, ranked by population.
    // Returns up to `limit` { name, cc, country, lat, lon, pop } objects.
    const search = (query, limit = 8) => {
      const q = String(query || '').trim().toLowerCase();
      if (!q) return [];
      const prefix = [], contains = [];
      for (let i = 0; i < lower.length; i++) {
        const idx = lower[i].indexOf(q);
        if (idx === 0) prefix.push(i);
        else if (idx > 0) contains.push(i);
      }
      const byPop = (a, b) => pops[b] - pops[a];
      prefix.sort(byPop);
      contains.sort(byPop);
      return prefix.concat(contains).slice(0, limit).map((i) => ({
        name: names[i],
        cc: cc[i],
        country: countryName(cc[i]),
        lat: lats[i],
        lon: lons[i],
        pop: pops[i],
      }));
    };

    return { names, cc, lats, lons, pops, countryName, search, count: names.length };
  })();
